'use strict';

/**
* Take elements from one of two strided arrays depending on a condition.
*
* @module @stdlib/blas/ext/base/gwhere
*
* @example
* import gwhere from '@stdlib/blas/ext/base/gwhere';
*
* var condition = [ 1, 0, 1 ];
* var x = [ 1.0, 2.0, 3.0 ];
* var y = [ 4.0, 5.0, 6.0 ];
* var out = [ 0.0, 0.0, 0.0 ];
*
* gwhere( 3, condition, 1, x, 1, y, 1, out, 1 );
* // out => [ 1.0, 5.0, 3.0 ]
*
* @example
* import gwhere from '@stdlib/blas/ext/base/gwhere';
*
* var condition = [ 1, 0, 1, 0 ];
* var x = [ 1.0, 2.0, 3.0, 4.0 ];
* var y = [ 5.0, 6.0, 7.0, 8.0 ];
* var out = [ 0.0, 0.0, 0.0, 0.0 ];
*
* gwhere.ndarray( 4, condition, 1, 0, x, 1, 0, y, 1, 0, out, 1, 0 );
* // out => [ 1.0, 6.0, 3.0, 8.0 ]
*/

// MODULES //

import setReadOnly from '@stdlib/utils/define-nonenumerable-read-only-property';
import main from './main.js';
import ndarray from './ndarray.js';


// MAIN //

setReadOnly( main, 'ndarray', ndarray );


// EXPORTS //

export default main;
